// ═══════════════════════════════════════════════════════
// CLASSIFICAR LEADS — Primeiro contato + Follow-up
// Pula: PROCESSANDO, ERRO, OPT_OUT
// Follow-up: FU1 em D+3, FU2 em D+7
// ═══════════════════════════════════════════════════════
const NOME_CONSULTOR = 'Maya';

const now = new Date();
const items = $input.all();
const result = [];

for (const item of items) {
  const d = item.json;
  const status = (d['ENVIOU MSG'] || '').toString().trim().toUpperCase();
  const optout = (d['OPT_OUT'] || '').toString().trim().toUpperCase();

  if (optout === 'SIM') continue;
  if (status === 'PROCESSANDO' || status === 'ERRO') continue;

  if (!status || status === 'PENDENTE') {
    result.push({ json: { ...d, tipo_disparo: 'primeiro_contato', NOME_CONSULTOR } });
  } else if (status === 'FEITO') {
    const dataEnvio = (d['DATA DO ENVIO'] || '').toString().trim();
    if (!dataEnvio) continue;
    const parts = dataEnvio.split(' ')[0].split('/');
    if (parts.length < 3) continue;
    const sendDate = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
    const daysSince = Math.floor((now - sendDate) / 86400000);
    const followups = parseInt(d.FOLLOWUP_COUNT || '0') || 0;

    if (followups === 0 && daysSince >= 3) {
      result.push({ json: { ...d, tipo_disparo: 'followup_1', NOME_CONSULTOR } });
    } else if (followups === 1 && daysSince >= 7) {
      result.push({ json: { ...d, tipo_disparo: 'followup_2', NOME_CONSULTOR } });
    }
  }
}

return result;

// ═══════════════════════════════════════════════════════
// HIGIENIZAR DADOS — Telefone, Nome, Empresa + DDD/Região
// ═══════════════════════════════════════════════════════
const skip = /^(ass|cont|contab|contábil|emp|serv|ltda|eireli|me|ss|dpto|dep)/i;

const DDD_REGIAO = {
  '11': 'SP-Capital', '12': 'SP-ValeParaiba', '13': 'SP-Litoral', '14': 'SP-Bauru',
  '15': 'SP-Sorocaba', '16': 'SP-Ribeirao', '17': 'SP-SJRioPreto', '18': 'SP-PPresidente',
  '19': 'SP-Campinas',
  '21': 'RJ-Capital', '22': 'RJ-Interior', '24': 'RJ-Interior',
  '31': 'MG-BH', '32': 'MG-JuizFora', '33': 'MG-GVale', '34': 'MG-Uberlandia',
  '35': 'MG-PocosVarginha', '37': 'MG-DivinoGov', '38': 'MG-Montes',
  '41': 'PR-Curitiba', '42': 'PR-PontaGrossa', '43': 'PR-Londrina',
  '44': 'PR-Maringa', '45': 'PR-CasOeste', '46': 'PR-PBranco',
  '47': 'SC-Joinville', '48': 'SC-Florianopolis', '49': 'SC-Chapeco',
  '51': 'RS-PortoAlegre', '53': 'RS-Pelotas', '54': 'RS-Caxias', '55': 'RS-SantaMaria',
  '61': 'DF', '62': 'GO-Goiania', '63': 'TO', '64': 'GO-Interior',
  '65': 'MT-Cuiaba', '66': 'MT-Interior', '67': 'MS',
  '71': 'BA-Salvador', '73': 'BA-Ilheus', '74': 'BA-Juazeiro', '75': 'BA-Feira',
  '77': 'BA-VConquista', '79': 'SE',
  '81': 'PE-Recife', '82': 'AL', '83': 'PB', '84': 'RN', '85': 'CE-Fortaleza',
  '86': 'PI', '87': 'PE-Interior', '88': 'CE-Interior', '89': 'PI-Interior',
  '91': 'PA-Belem', '92': 'AM-Manaus', '93': 'PA-Santarem', '94': 'PA-Maraba',
  '95': 'RR', '96': 'AP', '97': 'AM-Interior', '98': 'MA-SLuis', '99': 'MA-Interior'
};

return $input.all().map(item => {
  const d = item.json;

  let phone = (d.WHATSAPP || '').toString().replace(/\D/g, '');
  if (phone.length === 11 || phone.length === 10) phone = '55' + phone;
  if (phone.startsWith('5555')) phone = phone.slice(2);
  const telefone_valido = phone.length >= 12 && phone.length <= 13 && phone.startsWith('55');

  let ddd = '';
  let regiao = '';
  if (telefone_valido) {
    ddd = phone.substring(2, 4);
    regiao = DDD_REGIAO[ddd] || 'Outro';
  }

  let nomeRaw = (d.NOME || '').toString().trim();
  nomeRaw = nomeRaw.replace(/^[+\-\d\s*×÷=.]+/, '').trim();
  nomeRaw = nomeRaw.replace(/\s*[+×÷=]+\s*.*/g, '').trim();
  nomeRaw = nomeRaw.replace(/\(.*?\)/g, '').trim();
  let primeiro_nome = nomeRaw.split(/[\s,;\/]+/)[0] || '';
  if (/^\d+$/.test(primeiro_nome) || primeiro_nome.length < 3) primeiro_nome = '';
  if (skip.test(primeiro_nome)) primeiro_nome = '';
  if (primeiro_nome && primeiro_nome === primeiro_nome.toUpperCase()) {
    primeiro_nome = primeiro_nome.charAt(0).toUpperCase() + primeiro_nome.slice(1).toLowerCase();
  }

  let empresa = (d.EMPRESA || '').toString().trim();
  if (empresa.length < 3) empresa = '';

  if (!primeiro_nome && empresa) {
    const palavras = empresa.split(/\s+/);
    if (palavras.length <= 3) {
      const candidato = palavras[0];
      if (candidato.length >= 3 && !/^\d+$/.test(candidato) && !skip.test(candidato)) {
        primeiro_nome = candidato;
        if (primeiro_nome === primeiro_nome.toUpperCase()) {
          primeiro_nome = primeiro_nome.charAt(0).toUpperCase() + primeiro_nome.slice(1).toLowerCase();
        }
      }
    }
  }

  let nome_saudacao = primeiro_nome;
  if (!nome_saudacao && empresa) {
    nome_saudacao = 'pessoal da ' + empresa;
  }

  let produto = (d['PRODUTO DE INTERESSE'] || '').toString().trim();

  return { json: { ...d, telefone_limpo: phone, telefone_valido, nome_limpo: primeiro_nome, nome_saudacao, empresa_limpa: empresa, produto_limpo: produto, ddd, regiao } };
}).filter(item => item.json.telefone_valido);

// ═══════════════════════════════════════════════════════
// WARMUP PROGRESSIVO — Volume dinâmico por semana
// ▶ Ajuste DATA_INICIO_WARMUP na primeira ativação
// ═══════════════════════════════════════════════════════
const DATA_INICIO_WARMUP = '2026-04-10';
const EXECUCOES_POR_DIA = 4;

const inicio = new Date(DATA_INICIO_WARMUP);
const agora = new Date();
const dias = Math.max(0, Math.floor((agora - inicio) / 86400000));

let maxPorDia;
if (dias < 7)       maxPorDia = 20;
else if (dias < 14) maxPorDia = 50;
else if (dias < 21) maxPorDia = 100;
else if (dias < 28) maxPorDia = 200;
else                maxPorDia = 300;

const maxPorExec = Math.ceil(maxPorDia / EXECUCOES_POR_DIA);

const items = $input.all();
const primeiro = items.filter(i => i.json.tipo_disparo === 'primeiro_contato');
const followup = items.filter(i => i.json.tipo_disparo !== 'primeiro_contato');

const maxP = Math.ceil(maxPorExec * 0.7);
const maxF = Math.floor(maxPorExec * 0.3);

const selecionados = [
  ...primeiro.slice(0, maxP),
  ...followup.slice(0, maxF)
];

return selecionados.slice(0, maxPorExec);

// ═══════════════════════════════════════════════════════
// PREPARAR CONTEXTO — v7-final
// Monta: dados do lead + prompts IA + fallback determinístico
// FU2 envia catálogo PDF
// ═══════════════════════════════════════════════════════
const item = $input.first().json;
const nome = item.nome_saudacao || '';
const empresa = item.empresa_limpa || '';
const consultor = item.NOME_CONSULTOR || 'Maya';
const tipo = item.tipo_disparo || 'primeiro_contato';
const contexto = (item.CONTEXTO || '').toString().trim();
const tom = (item.TOM || '').toString().trim().toLowerCase();
const objetivo = (item.OBJETIVO_DISPARO || '').toString().trim().toLowerCase();
const varianteOriginal = (item.VARIANTE || '').toString().trim().toUpperCase();

const CATALOGO_URL = 'https://drive.google.com/uc?export=download&id=1W2iTzt0rxmw7yEw69VZKiKOHc6ffKeHL';
const CATALOGO_NOME = 'Catálogo de Produtos - Federal Malotes.pdf';

const variants = ['A', 'B', 'C'];
const variante = tipo === 'primeiro_contato'
  ? variants[Math.floor(Math.random() * 3)]
  : varianteOriginal || variants[Math.floor(Math.random() * 3)];

let angulo, gancho, detalhe;
if (variante === 'A') {
  angulo = 'malotes';
  gancho = 'malotes e materiais pra transporte de documentos';
  detalhe = 'separação por cliente, organização de entregas e devoluções';
} else if (variante === 'B') {
  angulo = 'quadro_fiscal';
  gancho = 'quadros fiscais, porta alvarás e materiais de conformidade';
  detalhe = 'conformidade legal, documentos em local visível como determina a lei';
} else {
  angulo = 'corporativo';
  gancho = 'agendas, cadernos e materiais personalizados com a marca do escritório';
  detalhe = 'imagem profissional, relacionamento com clientes, presença de marca';
}

const saudacao = nome ? 'Oi, ' + nome + ', tudo bem?' : 'Oi, tudo bem?';
const temEmpresaNoNome = nome.startsWith('pessoal');
let refExtra = '';
if (contexto && (contexto.includes('logo') || contexto.includes('personalização'))) {
  refExtra = ', inclusive com personalização da marca';
}
const maxChars = tipo === 'primeiro_contato' ? 500 : 350;

let enviar_catalogo = false;
let catalogo_url = '';
if (tipo === 'followup_2' && CATALOGO_URL && !CATALOGO_URL.startsWith('CONFIGURAR')) {
  enviar_catalogo = true;
  catalogo_url = CATALOGO_URL;
}

// ═══ FALLBACK DETERMINÍSTICO ═══
let fallback_msg = '';

if (tipo === 'primeiro_contato') {
  if (variante === 'A') {
    fallback_msg = empresa && !temEmpresaNoNome
      ? saudacao + '\n\nAqui é a ' + consultor + ', assistente da Federal Malotes.\n\nVi que a ' + empresa + ' é do ramo contábil. A gente fornece ' + gancho + refExtra + ' que ajudam bastante na organização do dia a dia do escritório.\n\nPosso te mostrar alguns modelos que costumam fazer sentido pra vocês?'
      : saudacao + '\n\nAqui é a ' + consultor + ', assistente da Federal Malotes.\n\nA gente trabalha com muitos escritórios contábeis fornecendo ' + gancho + refExtra + ' que ajudam na organização do dia a dia — ' + detalhe + '.\n\nPosso te mostrar alguns modelos que costumam fazer sentido pra contabilidade?';
  } else if (variante === 'B') {
    fallback_msg = empresa && !temEmpresaNoNome
      ? saudacao + '\n\nAqui é a ' + consultor + ', da Federal Malotes.\n\nTrabalho com escritórios como a ' + empresa + ' que precisam de ' + gancho + ' pra manter tudo em ordem com a legislação.\n\nVocês já usam algum material assim no escritório?'
      : saudacao + '\n\nAqui é a ' + consultor + ', da Federal Malotes.\n\nTrabalho com escritórios contábeis que precisam de ' + gancho + ' pra manter tudo em ordem com a legislação.\n\nVocês já usam algum material assim no escritório?';
  } else {
    fallback_msg = empresa && !temEmpresaNoNome
      ? saudacao + '\n\n' + consultor + ' aqui, da Federal Malotes.\n\nA gente produz ' + gancho + refExtra + ' com a marca do escritório. Vi que a ' + empresa + ' é do ramo contábil — muitos escritórios usam pra fortalecer a marca e impressionar os clientes.\n\nFaz sentido eu te mostrar como funciona?'
      : saudacao + '\n\n' + consultor + ' aqui, da Federal Malotes.\n\nA gente produz ' + gancho + refExtra + ' com a marca do escritório. Muitos contadores usam pra fortalecer a marca e impressionar os clientes.\n\nFaz sentido eu te mostrar como funciona?';
  }
} else if (tipo === 'followup_1') {
  const hi = nome ? 'Oi, ' + nome + '!' : 'Oi!';
  fallback_msg = hi + '\n\n' + consultor + ' aqui, da Federal Malotes. Te mandei uma mensagem uns dias atrás sobre ' + gancho + ' pra escritórios contábeis.\n\nQuer que eu te mande uns modelos pra dar uma olhada sem compromisso?';
} else if (tipo === 'followup_2') {
  const hi = nome ? 'Oi, ' + nome + '!' : 'Oi!';
  fallback_msg = hi + '\n\nSeparei um material rápido com alguns exemplos do que a gente produz pra escritórios contábeis.\n\nEstou te enviando aqui. Se fizer sentido, posso te mostrar o que costuma funcionar melhor pro seu caso.';
}

if (fallback_msg.length > maxChars) {
  const cut = fallback_msg.substring(0, maxChars - 3);
  const nl = cut.lastIndexOf('\n');
  fallback_msg = nl > 200 ? cut.substring(0, nl) : cut + '...';
}

// ═══ PROMPTS PARA IA ═══
const focoAngulo = angulo === 'malotes'
  ? 'organização e transporte de documentos'
  : angulo === 'quadro_fiscal'
    ? 'conformidade legal e documentos obrigatórios'
    : 'imagem profissional e presença de marca';

const system_prompt = `Você é Maya, assistente comercial da Federal Malotes. Escreve mensagens de WhatsApp para escritórios contábeis.

REGRAS ABSOLUTAS:
- Escreva como pessoa real da equipe comercial, NUNCA revele que é IA
- Máximo ${maxChars} caracteres (RIGOROSO)
- PROIBIDO inventar: preços, prazos, descontos, promoções, urgência falsa
- PROIBIDO: emojis excessivos (máximo 1 se soar natural), listas, bullets, formatação rica
- PROIBIDO: parecer catálogo, panfleto ou spam
- PROIBIDO: mencionar que o contato visitou o site ou entrou em contato anteriormente (é base fria)
- OBRIGATÓRIO: terminar com UMA pergunta curta e fácil de responder
- Tom: consultivo, natural, humano, como colega de trabalho
- Se apresente como "${consultor}, da Federal Malotes" (ou variação natural)
- Foco deste disparo: ${focoAngulo}
- A Federal Malotes tem +30 anos e atende escritórios contábeis em todo o Brasil`;

let user_prompt = '';
const nomeLabel = nome || 'sem nome disponível';
const empresaLabel = empresa || 'não informada';

if (tipo === 'primeiro_contato') {
  user_prompt = `Gere UMA mensagem de PRIMEIRO CONTATO por WhatsApp para uma base fria (sem contato prévio).

Lead: ${nomeLabel}
Empresa: ${empresaLabel}
Produto foco: ${gancho}
Detalhe: ${detalhe}${contexto ? '\nContexto: ' + contexto : ''}${tom ? '\nTom desejado: ' + tom : ''}${objetivo ? '\nObjetivo: ' + objetivo : ''}

A mensagem deve:
1. Cumprimentar usando "${saudacao}" ou variação
2. Apresentar a ${consultor} como da Federal Malotes
3. Conectar com o dia a dia do escritório contábil
4. Mencionar ${gancho} de forma natural
5. Terminar com pergunta aberta simples
6. NÃO mencionar visita a site ou contato anterior

NÃO copie templates. Escreva de forma única e natural.`;

} else if (tipo === 'followup_1') {
  user_prompt = `Gere UM FOLLOW-UP LEVE (a pessoa não respondeu há 3 dias).

Lead: ${nomeLabel}
Empresa: ${empresaLabel}
Produto mencionado antes: ${gancho}

A mensagem deve:
1. Ser curta e leve (máximo 350 chars)
2. Mencionar que mandou mensagem antes
3. Oferecer enviar modelos/exemplos sem compromisso
4. Zero pressão

NÃO copie templates. Escreva de forma única.`;

} else if (tipo === 'followup_2') {
  user_prompt = `Gere UM FOLLOW-UP FINAL (última tentativa). Um catálogo PDF será enviado junto.

Lead: ${nomeLabel}
Empresa: ${empresaLabel}
Produto: ${gancho}

A mensagem deve:
1. Ser a última tentativa (deixar claro sem dramatizar)
2. Muito curta (máximo 350 chars)
3. Mencionar que está enviando um material/catálogo
4. Tom leve e sem pressão
5. Perguntar se faz sentido conversar

NÃO copie templates. Escreva de forma única.`;
}

const varLabel = tipo === 'primeiro_contato' ? variante : tipo.toUpperCase();

return [{ json: {
  ...item,
  saudacao, gancho, detalhe, angulo,
  variante: varLabel,
  enviar_catalogo, catalogo_url,
  catalogo_nome: CATALOGO_NOME,
  maxChars, fallback_msg, system_prompt, user_prompt, consultor
}}];

// ═══════════════════════════════════════════════════════
// BRIDGE — Normaliza saída do OpenAI e recupera contexto
// ═══════════════════════════════════════════════════════
const contexto = $('prepararContexto').first().json;
const openaiOutput = $input.first().json;

let msg_ia = '';
if (typeof openaiOutput.text === 'string') {
  msg_ia = openaiOutput.text.trim();
} else if (openaiOutput.message?.content) {
  msg_ia = openaiOutput.message.content.trim();
} else if (openaiOutput.choices?.[0]?.message?.content) {
  msg_ia = openaiOutput.choices[0].message.content.trim();
} else if (typeof openaiOutput.content === 'string') {
  msg_ia = openaiOutput.content.trim();
}

return [{ json: {
  ...contexto,
  msg_ia,
  erro_ia: msg_ia ? '' : 'OpenAI retornou vazio ou formato inesperado'
}}];

// ═══════════════════════════════════════════════════════
// VALIDAR MENSAGEM — v7-final
// Valida output da IA. Se inválido, usa fallback.
// GARANTE: mensagem_final NUNCA é vazio/null/undefined.
// ═══════════════════════════════════════════════════════
const item = $input.first().json;
const maxChars = item.maxChars || 500;
let msg = (item.msg_ia || '').toString().trim();
let fonte = 'ia';
let motivo_fallback = '';

// Validação 1: existe e tem tamanho mínimo?
if (!msg || msg.length < 30) {
  fonte = 'fallback';
  motivo_fallback = !msg ? 'msg_ia vazia' : 'msg_ia curta (' + msg.length + ' chars)';
  msg = '';
}

// Validação 2: termos proibidos (IA se revelando)
if (msg) {
  const proibidos = [
    'como ia', 'como assistente virtual', 'inteligência artificial',
    'sou um bot', 'sou uma ia', 'modelo de linguagem', 'chatgpt',
    'openai', 'anthropic', 'large language'
  ];
  for (const termo of proibidos) {
    if (msg.toLowerCase().includes(termo)) {
      fonte = 'fallback';
      motivo_fallback = 'termo proibido: "' + termo + '"';
      msg = '';
      break;
    }
  }
}

// Validação 3: referência indevida ao site (base fria)
if (msg) {
  const siteTermos = ['pelo site', 'no site', 'acessou', 'visitou', 'entrou em contato pelo'];
  for (const termo of siteTermos) {
    if (msg.toLowerCase().includes(termo)) {
      fonte = 'fallback';
      motivo_fallback = 'referencia indevida ao site: "' + termo + '"';
      msg = '';
      break;
    }
  }
}

// Validação 4: valores nulos literais
if (msg && (msg.includes('undefined') || msg.includes('null') || msg.includes('[object'))) {
  fonte = 'fallback';
  motivo_fallback = 'contém valores nulos literais';
  msg = '';
}

// Validação 5: repetição excessiva
if (msg) {
  const words = msg.split(/\s+/);
  const freq = {};
  for (const w of words) {
    if (w.length > 4) freq[w.toLowerCase()] = (freq[w.toLowerCase()] || 0) + 1;
  }
  if (Object.values(freq).some(v => v > 5)) {
    fonte = 'fallback';
    motivo_fallback = 'repetição excessiva';
    msg = '';
  }
}

// Sanitização (se msg sobreviveu)
if (msg) {
  msg = msg.replace(/R\$\s*[\d.,]+/g, '[consulte valores]');
  if (msg.length > maxChars) {
    const cut = msg.substring(0, maxChars - 3);
    const nl = cut.lastIndexOf('\n');
    msg = nl > 200 ? cut.substring(0, nl) : cut + '...';
  }
}

// Aplicar fallback se necessário
if (!msg || fonte === 'fallback') {
  msg = (item.fallback_msg || '').toString().trim();
  fonte = 'fallback';
  if (!motivo_fallback) motivo_fallback = 'validação geral';
}

// Garantia absoluta — NUNCA VAZIO
if (!msg || msg.length < 10) {
  const c = item.consultor || item.NOME_CONSULTOR || 'Maya';
  msg = (item.saudacao || 'Oi, tudo bem?')
    + '\n\nAqui é a ' + c + ', assistente da Federal Malotes.'
    + '\n\nA gente trabalha com escritórios contábeis fornecendo materiais personalizados.'
    + '\n\nPosso te mostrar alguns modelos?';
  fonte = 'fallback_emergencia';
  motivo_fallback = 'fallback principal falhou';
}

// Anti-alucinação final
msg = msg.replace(/R\$\s*[\d.,]+/g, '[consulte valores]');

return [{ json: {
  ...item,
  mensagem_final: msg,
  fonte_msg: fonte,
  motivo_fallback: motivo_fallback || '',
  erro_ia: item.erro_ia || ''
}}];

const lead = $('validarMensagem').first().json;

const MIN_MINUTES = 2;
const MAX_MINUTES = 10;
const prev = Number(lead.TempoMsg);

function randInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

let delaySeconds;
let tries = 0;
do {
  delaySeconds = randInt(MIN_MINUTES, MAX_MINUTES) * 60;
  tries++;
} while (Number.isFinite(prev) && delaySeconds === prev && tries < 50);

if (Number.isFinite(prev) && delaySeconds === prev) {
  const up = prev + 60;
  const down = prev - 60;
  if (up <= MAX_MINUTES * 60) delaySeconds = up;
  else if (down >= MIN_MINUTES * 60) delaySeconds = down;
}

return [{ json: { ...lead, delaySeconds } }];
